storyboard.visual_content:
graph TD
    A[Internet Data (Texts, Code, etc.)] --> B{Data Collection & Filtering};
    B --> C{Training Dataset};
    C -- Up to DATE_X --> D[LLM Training Process];
    D --> E[Trained LLM (Knowledge Cutoff: DATE_X)];
    E -- Cannot access --> F[New Information Post-DATE_X];

    style E fill:#f9f,stroke:#333,stroke-width:2px;
    style F fill:#ccc,stroke:#999,stroke-width:1px,color:#333;
    linkStyle 4 stroke:#f00,stroke-width:2px,stroke-dasharray: 5 5;
